        if key in ALLOWED_FIELDS:
            vehicle[key] = updates[key]

def update_employee_record(employee: dict, updates: dict, is_admin: bool):
    if is_admin:
        for key, value in updates.items():
            employee[key] = value
    else:
        for key, value in updates.items():
            if key in EDITABLE_FIELDS:
                employee[key] = value

from urllib.parse import urlparse
ALLOWED_REDIRECT_DOMAINS = ["trusted-redirect.com", "partner.com"]

def handle_user_redirect(user_url: str):
    parsed_url = urlparse(user_url)
    if not parsed_url.scheme or not parsed_url.netloc:
        return False
    domain = parsed_url.netloc.split(':')[0]
    if domain in ALLOWED_REDIRECT_DOMAINS:
        return parsed_url.geturl()
    return False

from urllib.parse import urlparse
TRUSTED_IMAGE_HOSTS = ["img.example.com", "cdn.trusted.com", "images.hosting.com"]
ALLOWED_SCHEMES = ["http", "https"]

def resolve_image_url(image_url: str):
    parsed_url = urlparse(image_url)
    if parsed_url.scheme not in ALLOWED_SCHEMES:
        return None
    netloc = parsed_url.netloc
    if ':' in netloc:
        domain_part = netloc.split(':', 1)[0]
    else:
        domain_part = netloc
    if domain_part not in TRUSTED_IMAGE_HOSTS:
        return None
    return image_url

